"use strict";(self.webpackChunkshields_io=self.webpackChunkshields_io||[]).push([[48130],{59964(t){t.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"simple-icons-16","metadata":{"permalink":"/blog/simple-icons-16","editUrl":"https://github.com/badges/shields/tree/master/frontend/blog/2025-12-03-simple-icons-16.md","source":"@site/blog/2025-12-03-simple-icons-16.md","title":"Simple Icons 16","description":"Logos on Shields.io are provided by Simple Icons. We\'ve recently upgraded to Simple Icons 16. This release removes 44 icons and renames 2. A full list of the changes can be found in the release notes.","date":"2025-12-03T00:00:00.000Z","tags":[],"readingTime":0.36,"hasTruncateMarker":false,"authors":[{"name":"LitoMore","title":"Shields.io Core Team","url":"https://github.com/LitoMore","image_url":"https://avatars.githubusercontent.com/u/8186898","imageURL":"https://avatars.githubusercontent.com/u/8186898","socials":{},"key":null,"page":null}],"frontMatter":{"slug":"simple-icons-16","title":"Simple Icons 16","authors":{"name":"LitoMore","title":"Shields.io Core Team","url":"https://github.com/LitoMore","image_url":"https://avatars.githubusercontent.com/u/8186898","imageURL":"https://avatars.githubusercontent.com/u/8186898"},"tags":[]},"unlisted":false,"nextItem":{"title":"Supply chain vulnerability in eslint-config-prettier","permalink":"/blog/CVE-2025-54313"}},"content":"Logos on Shields.io are provided by Simple Icons. We\'ve recently upgraded to Simple Icons 16. This release removes 44 icons and renames 2. A full list of the changes can be found in the [release notes](https://github.com/simple-icons/simple-icons/releases/tag/16.0.0).\\n\\nPlease remember that we are just consumers of Simple Icons. Decisions about changes and removals are made by the [SimpleIcons](https://github.com/simple-icons/simple-icons) project."},{"id":"CVE-2025-54313","metadata":{"permalink":"/blog/CVE-2025-54313","editUrl":"https://github.com/badges/shields/tree/master/frontend/blog/2025-07-26-CVE-2025-54313.md","source":"@site/blog/2025-07-26-CVE-2025-54313.md","title":"Supply chain vulnerability in eslint-config-prettier","description":"A recent vulnerability in the eslint-config-prettier package, identified as CVE-2025-54313, has raised concerns about potential remote code execution (RCE) attacks. This vulnerability specifically affects Windows users and has been classified as high severity.","date":"2025-07-26T00:00:00.000Z","tags":[],"readingTime":1.1,"hasTruncateMarker":false,"authors":[{"name":"jNullj","title":"Shields.io Core Team","url":"https://github.com/jNullj","image_url":"https://avatars.githubusercontent.com/u/15849761","imageURL":"https://avatars.githubusercontent.com/u/15849761","socials":{},"key":null,"page":null}],"frontMatter":{"slug":"CVE-2025-54313","title":"Supply chain vulnerability in eslint-config-prettier","authors":{"name":"jNullj","title":"Shields.io Core Team","url":"https://github.com/jNullj","image_url":"https://avatars.githubusercontent.com/u/15849761","imageURL":"https://avatars.githubusercontent.com/u/15849761"},"tags":[]},"unlisted":false,"prevItem":{"title":"Simple Icons 16","permalink":"/blog/simple-icons-16"},"nextItem":{"title":"Simple Icons 15","permalink":"/blog/simple-icons-15"}},"content":"A recent vulnerability in the `eslint-config-prettier` package, identified as [CVE-2025-54313](https://www.endorlabs.com/learn/cve-2025-54313-eslint-config-prettier-compromise----high-severity-but-windows-only), has raised concerns about potential remote code execution (RCE) attacks. This vulnerability specifically affects Windows users and has been classified as high severity.\\n\\nOther packages vulnerable to this issue that shields uses in our supply chain include:\\n\\n- `eslint-plugin-prettier`\\n- `synckit`\\n- `@pkgr/core`\\n- `napi-postinstall`\\n\\nNone of the vulnerable versions seems to be used in our codebase, and to date, upstream removed vulnerable versions from npm. However, as we used `^` prefix for these package versions, anyone running `npm install` on a Windows machine before the fix was applied could have been affected. For example, contributors & devs of forks. With the risk being malicious code executed on the user\'s machine, we recommend that anyone who has run `npm install` on a Windows machine with these packages check their systems for any signs of compromise.\\n\\nThe issue does not seem to affect our CI environment, as our only Windows job `test-main` uses `npm ci` which does not install packages with the `^` prefix, and thus does not install vulnerable versions.\\n\\nCurrently, we are not aware of any issues in our production environment related to this vulnerability. We will continue to monitor the situation."},{"id":"simple-icons-15","metadata":{"permalink":"/blog/simple-icons-15","editUrl":"https://github.com/badges/shields/tree/master/frontend/blog/2025-06-06-simpleicons15.md","source":"@site/blog/2025-06-06-simpleicons15.md","title":"Simple Icons 15","description":"Logos on Shields.io are provided by SimpleIcons. We\'ve recently upgraded to SimpleIcons 15. This release removes 50 icons and renames 7. A full list of the changes can be found in the release notes.","date":"2025-06-06T00:00:00.000Z","tags":[],"readingTime":0.35,"hasTruncateMarker":false,"authors":[{"name":"chris48s","title":"Shields.io Core Team","url":"https://github.com/chris48s","image_url":"https://avatars.githubusercontent.com/u/6025893","imageURL":"https://avatars.githubusercontent.com/u/6025893","socials":{},"key":null,"page":null}],"frontMatter":{"slug":"simple-icons-15","title":"Simple Icons 15","authors":{"name":"chris48s","title":"Shields.io Core Team","url":"https://github.com/chris48s","image_url":"https://avatars.githubusercontent.com/u/6025893","imageURL":"https://avatars.githubusercontent.com/u/6025893"},"tags":[]},"unlisted":false,"prevItem":{"title":"Supply chain vulnerability in eslint-config-prettier","permalink":"/blog/CVE-2025-54313"},"nextItem":{"title":"Simple Icons 14","permalink":"/blog/simple-icons-14"}},"content":"Logos on Shields.io are provided by SimpleIcons. We\'ve recently upgraded to SimpleIcons 15. This release removes 50 icons and renames 7. A full list of the changes can be found in the [release notes](https://github.com/simple-icons/simple-icons/releases/tag/15.0.0).\\n\\nPlease remember that we are just consumers of SimpleIcons. Decisions about changes and removals are made by the [SimpleIcons](https://github.com/simple-icons/simple-icons) project."},{"id":"simple-icons-14","metadata":{"permalink":"/blog/simple-icons-14","editUrl":"https://github.com/badges/shields/tree/master/frontend/blog/2024-12-27-simpleicons14.md","source":"@site/blog/2024-12-27-simpleicons14.md","title":"Simple Icons 14","description":"Logos on Shields.io are provided by SimpleIcons. We\'ve recently upgraded to SimpleIcons 14. This release removes 53 icons and renames 6:","date":"2024-12-27T00:00:00.000Z","tags":[],"readingTime":0.85,"hasTruncateMarker":false,"authors":[{"name":"jNullj","title":"Shields.io Core Team","url":"https://github.com/jNullj","image_url":"https://avatars.githubusercontent.com/u/15849761","imageURL":"https://avatars.githubusercontent.com/u/15849761","socials":{},"key":null,"page":null}],"frontMatter":{"slug":"simple-icons-14","title":"Simple Icons 14","authors":{"name":"jNullj","title":"Shields.io Core Team","url":"https://github.com/jNullj","image_url":"https://avatars.githubusercontent.com/u/15849761","imageURL":"https://avatars.githubusercontent.com/u/15849761"},"tags":[]},"unlisted":false,"prevItem":{"title":"Simple Icons 15","permalink":"/blog/simple-icons-15"},"nextItem":{"title":"How shields.io uses the GitHub API","permalink":"/blog/token-pool"}},"content":"Logos on Shields.io are provided by SimpleIcons. We\'ve recently upgraded to SimpleIcons 14. This release removes 53 icons and renames 6:\\n\\nRenames:\\n\\n- D3.js to D3\\n- Tencent QQ to QQ\\n- T-Mobile to Deutsche Telekom\\n- Nuxt.js to Nuxt\\n- smash.gg start.gg\\n- Tutanota to Tuta\\n\\nRemovals:\\n\\n- Adobe\\n- Adobe Acrobat Reader\\n- Adobe After Effects\\n- Adobe Audition\\n- Adobe Creative Cloud\\n- Adobe Dreamweaver\\n- Adobe Fonts\\n- Adobe Illustrator\\n- Adobe InDesign\\n- Adobe Lightroom\\n- Adobe Lightroom Classic\\n- Adobe Photoshop\\n- Adobe Premiere Pro\\n- Adobe XD\\n- ASKfm\\n- Caffeine\\n- CKEditor 4\\n- Cliqz\\n- Coil\\n- del.icio.us\\n- El Jueves\\n- Ello\\n- FeatHub\\n- Fluxus\\n- Foursquare City Guide\\n- Funimation\\n- Game & Watch\\n- G\xe9ant\\n- Katacoda\\n- LinkedIn\\n- Magento\\n- Marketo\\n- Microgenetics\\n- Nintendo\\n- Nintendo 3DS\\n- Nintendo DS\\n- Nintendo GameCube\\n- Nintendo Switch\\n- Oracle\\n- Pok\xe9mon\\n- RadioPublic\\n- Realm\\n- Revue\\n- Skyrock\\n- Spinrilla\\n- StackPath\\n- Stitcher\\n- Studyverse\\n- Tableau\\n- Uptobox\\n- Wii\\n- Wii U\\n- Zerply\\n\\nMore detail can be found in the [release notes](https://github.com/simple-icons/simple-icons/releases/tag/14.0.0)\\n\\nPlease remember that we are just consumers of SimpleIcons. Decisions about changes and removals are made by the [SimpleIcons](https://github.com/simple-icons/simple-icons) project."},{"id":"token-pool","metadata":{"permalink":"/blog/token-pool","editUrl":"https://github.com/badges/shields/tree/master/frontend/blog/2024-11-14-token-pool.md","source":"@site/blog/2024-11-14-token-pool.md","title":"How shields.io uses the GitHub API","description":"We serve a lot of badges which display information fetched from the GitHub API. When I say a lot, this varies a bit but in a typical hour we make hundreds of thousands of calls to the GitHub API.","date":"2024-11-14T00:00:00.000Z","tags":[],"readingTime":2.03,"hasTruncateMarker":false,"authors":[{"name":"chris48s","title":"Shields.io Core Team","url":"https://github.com/chris48s","image_url":"https://avatars.githubusercontent.com/u/6025893","imageURL":"https://avatars.githubusercontent.com/u/6025893","socials":{},"key":null,"page":null}],"frontMatter":{"slug":"token-pool","title":"How shields.io uses the GitHub API","authors":{"name":"chris48s","title":"Shields.io Core Team","url":"https://github.com/chris48s","image_url":"https://avatars.githubusercontent.com/u/6025893","imageURL":"https://avatars.githubusercontent.com/u/6025893"},"tags":[]},"unlisted":false,"prevItem":{"title":"Simple Icons 14","permalink":"/blog/simple-icons-14"},"nextItem":{"title":"Our response to RCE Security Advisory","permalink":"/blog/GHSA-rxvx-x284-4445"}},"content":"We serve a lot of badges which display information fetched from the GitHub API. When I say a lot, this varies a bit but in a typical hour we make hundreds of thousands of calls to the GitHub API.\\n\\nBut hang on. GitHub\'s API has rate limits.\\n\\nSpecifically, users can make up to [5,000 requests per hour](https://docs.github.com/en/rest/using-the-rest-api/rate-limits-for-the-rest-api?apiVersion=2022-11-28#primary-rate-limit-for-authenticated-users) to GitHub\'s v3/REST API. The v4/GraphQL also applies rate limits, but it is based on a slightly more complicated [points-based system](https://docs.github.com/en/graphql/overview/rate-limits-and-node-limits-for-the-graphql-api#primary-rate-limit).\\n\\nIn any case, we are clearly making many times more requests to GitHub\'s API than would be allowed with a single token.\\n\\nSo how are we doing that? Well, we have lots of tokens. To elaborate on that slightly, as a user of shields.io you can choose to share a token with us to help increase our rate limit. Here\'s how it works:\\n\\n- Authorize our [OAuth Application](https://img.shields.io/github-auth).\\n- This shares with us a GitHub token which has read-only access to public data. We only ask for the minimum permissions necessary. Authorizing the OAuth app doesn\'t allow us access to your private data or allow us to perform any actions on your behalf.\\n- Your token is added to a pool of tokens shared by other users like you.\\n- When we need to make a request to the GitHub API, we pick one of the tokens from our pool. We only make a handful of requests with each token before picking another from the pool.\\n- If you ever decide you would not like to continue sharing a token with us, you can revoke the Shields.io OAuth app at https://github.com/settings/applications. You can do this at any time. This will de-activate the token you have shared with us and we\'ll remove it from the pool.\\n\\nThis method allows us (with your help) to make hundreds of thousands of request per hour to the GitHub API. Because we have thousands of tokens in the pool and we only make a few requests with each one before picking another token from the pool, most users don\'t notice any meaningful impact on their available rate limit as a result of authorizing our app."},{"id":"GHSA-rxvx-x284-4445","metadata":{"permalink":"/blog/GHSA-rxvx-x284-4445","editUrl":"https://github.com/badges/shields/tree/master/frontend/blog/2024-09-25-rce.md","source":"@site/blog/2024-09-25-rce.md","title":"Our response to RCE Security Advisory","description":"We\'ve just published a critical security advisory relating to a Remote Code Execution vulnerability in Dynamic JSON/TOML/YAML badges//github.com/badges/shields/security/advisories/GHSA-rxvx-x284-4445 Thanks to @nickcopi for his help with this.","date":"2024-09-25T00:00:00.000Z","tags":[],"readingTime":16.45,"hasTruncateMarker":false,"authors":[{"name":"chris48s","title":"Shields.io Core Team","url":"https://github.com/chris48s","image_url":"https://avatars.githubusercontent.com/u/6025893","imageURL":"https://avatars.githubusercontent.com/u/6025893","socials":{},"key":null,"page":null}],"frontMatter":{"slug":"GHSA-rxvx-x284-4445","title":"Our response to RCE Security Advisory","authors":{"name":"chris48s","title":"Shields.io Core Team","url":"https://github.com/chris48s","image_url":"https://avatars.githubusercontent.com/u/6025893","imageURL":"https://avatars.githubusercontent.com/u/6025893"},"tags":[]},"unlisted":false,"prevItem":{"title":"How shields.io uses the GitHub API","permalink":"/blog/token-pool"},"nextItem":{"title":"Sunsetting Shields custom logos","permalink":"/blog/sunsetting-shields-custom-logos"}},"content":"We\'ve just published a critical security advisory relating to a Remote Code Execution vulnerability in Dynamic JSON/TOML/YAML badges: https://github.com/badges/shields/security/advisories/GHSA-rxvx-x284-4445 Thanks to [@nickcopi](https://github.com/nickcopi) for his help with this.\\n\\nIf you self-host your own instance of Shields you should upgrade to [server-2024-09-25](https://hub.docker.com/layers/shieldsio/shields/server-2024-09-25/images/sha256-28aaea75049e325c9f1d63c8a8b477fc387d3d3fe35b933d6581487843cd610f?context=explore) or later as soon as possible to protect your instance.\\n\\nThis is primarily a concern for self-hosting users. However this does also have a couple of knock-on implications for some users of shields.io itself.\\n\\n## 1. Users who have authorized the Shields.io GitHub OAuth app\\n\\nWhile we have taken steps to close this vulnerability quickly after becoming aware of it, this attack vector has existed in our application for some time. We aren\'t aware of it having been actively exploited on shields.io. We also can\'t prove that it has not been exploited.\\n\\nWe don\'t log or track our users, so a breach offers a very limited attack surface against end users of shields.io. This is by design. One of the (few) information assets shields.io does hold is our GitHub token pool. This allows users to share a token with us by authorizing our OAuth app. Doing this gives us access to a token with read-only access to public data which we can use to increase our rate limit when making calls to the GitHub API.\\n\\nThe tokens we hold are not of high value to an attacker because they have read-only access to public data, but we can\'t say for sure they haven\'t been exfiltrated. If you\'ve donated a token in the past and want to revoke it, you can revoke the Shields.io OAuth app at https://github.com/settings/applications which will de-activate the token you have shared with us.\\n\\n## 2. Users of Dynamic JSON/TOML/YAML badges\\n\\nUp until now, we have been using https://github.com/dchester/jsonpath as our library querying documents using JSONPath expressions. [@nickcopi](https://github.com/nickcopi) responsibly reported to us how a prototype pollution vulnerability in this library could be exploited to construct a JSONPath expression allowing an attacker to perform remote code execution. This vulnerability was reported on the package\'s issue tracker but not flagged by security scanning tools. It seems extremely unlikely that this will be fixed in the upstream package despite being widely used. It also seems unlikely this package will receive any further maintenance in future, even in response to critical security issues. In order to resolve this issue, we needed to switch to a different JSONPath library. We\'ve decided to switch https://github.com/JSONPath-Plus/JSONPath using the `eval: false` option to disable script expressions.\\n\\nThis is an important security improvement and we have to make a change to protect the security of shields.io and users hosting their own instance of the application. However, this does come with some tradeoffs from a backwards-compatibility perspective.\\n\\n### Using `eval: false`\\n\\nUsing JSONPath-Plus with `eval: false` does disable some query syntax which relies on evaluating javascript expressions.\\n\\nFor example, it would previously have been possible to use a JSONPath query like `$..keywords[(@.length-1)]` against the document https://github.com/badges/shields/raw/master/package.json to select the last element from the keywords array https://github.com/badges/shields/blob/e237e40ab88b8ad4808caad4f3dae653822aa79a/package.json#L6-L12\\n\\nThis is now not a supported query.\\n\\nIn this particular case, you could rewrite that query to `$..keywords[-1:]` and obtain the same result, but that may not be possible in all cases. We do realise that this removes some functionality that previously worked but closing this remote code execution vulnerability is the top priority, especially since there will be workarounds in many cases.\\n\\n### Implementation Quirks\\n\\nHistorically, every JSONPath implementation has had its own idiosyncrasies. While most simple and common queries will behave the same way across different implementations, switching to another library will mean that some subset of queries may not work or produce different results.\\n\\nOne interesting thing that has happened in the world of JSONPath lately is RFC 9535 https://www.rfc-editor.org/rfc/rfc9535 which is an attempt to standardise JSONPath. As part of this mitigation, we did look at whether it would be possible to migrate to something that is RFC9535-compliant. However it is our assessment that the JavaScript community does not yet have a sufficiently mature/supported RFC9535-compliant JSONPath implementation. This means we are switching from one quirky implementation to another implementation with different quirks.\\n\\nAgain, this represents an unfortunate break in backwards-compatibility. However, it was necessary to prioritise closing off this remote code execution vulnerability over backwards-compatibility.\\n\\nAlthough we can not provide a precise migration guide, here is a table of query types where https://github.com/dchester/jsonpath and https://github.com/JSONPath-Plus/JSONPath are known to diverge from the consensus implementation. This is sourced from the excellent https://cburgmer.github.io/json-path-comparison/ While this is a long list, many of these inputs represent edge cases or pathological inputs rather than common usage.\\n\\n <details>\\n  <summary>Table</summary>\\n<table>\\n<thead>\\n<tr>\\n<th>Query Type</th>\\n<th>Example Query</th>\\n</tr>\\n</thead>\\n<tbody>\\n<tr>\\n<td>Array slice with large number for end and negative step</td>\\n<td><code>$[2:-113667776004:-1]</code></td>\\n</tr>\\n<tr>\\n<td>Array slice with large number for start end negative step</td>\\n<td><code>$[113667776004:2:-1]</code></td>\\n</tr>\\n<tr>\\n<td>Array slice with negative step</td>\\n<td><code>$[3:0:-2]</code></td>\\n</tr>\\n<tr>\\n<td>Array slice with negative step on partially overlapping array</td>\\n<td><code>$[7:3:-1]</code></td>\\n</tr>\\n<tr>\\n<td>Array slice with negative step only</td>\\n<td><code>$[::-2]</code></td>\\n</tr>\\n<tr>\\n<td>Array slice with open end and negative step</td>\\n<td><code>$[3::-1]</code></td>\\n</tr>\\n<tr>\\n<td>Array slice with open start and negative step</td>\\n<td><code>$[:2:-1]</code></td>\\n</tr>\\n<tr>\\n<td>Array slice with range of 0</td>\\n<td><code>$[0:0]</code></td>\\n</tr>\\n<tr>\\n<td>Array slice with step 0</td>\\n<td><code>$[0:3:0]</code></td>\\n</tr>\\n<tr>\\n<td>Array slice with step and leading zeros</td>\\n<td><code>$[010:024:010]</code></td>\\n</tr>\\n<tr>\\n<td>Bracket notation with empty path</td>\\n<td><code>$[]</code></td>\\n</tr>\\n<tr>\\n<td>Bracket notation with number on object</td>\\n<td><code>$[0]</code></td>\\n</tr>\\n<tr>\\n<td>Bracket notation with number on string</td>\\n<td><code>$[0]</code></td>\\n</tr>\\n<tr>\\n<td>Bracket notation with number -1</td>\\n<td><code>$[-1]</code></td>\\n</tr>\\n<tr>\\n<td>Bracket notation with quoted array slice literal</td>\\n<td><code>$[\':\']</code></td>\\n</tr>\\n<tr>\\n<td>Bracket notation with quoted closing bracket literal</td>\\n<td><code>$[\']\']</code></td>\\n</tr>\\n<tr>\\n<td>Bracket notation with quoted current object literal</td>\\n<td><code>$[\'@\']</code></td>\\n</tr>\\n<tr>\\n<td>Bracket notation with quoted escaped backslash</td>\\n<td><code>$[\'\\\\\\\\\']</code></td>\\n</tr>\\n<tr>\\n<td>Bracket notation with quoted escaped single quote</td>\\n<td><code>$[\'\\\\\'\']</code></td>\\n</tr>\\n<tr>\\n<td>Bracket notation with quoted root literal</td>\\n<td><code>$[\'$\']</code></td>\\n</tr>\\n<tr>\\n<td>Bracket notation with quoted special characters combined</td>\\n<td><code>$[\':@.\\"$,*\\\\\'\\\\\\\\\']</code></td>\\n</tr>\\n<tr>\\n<td>Bracket notation with quoted string and unescaped single quote</td>\\n<td><code>$[\'single\'quote\']</code></td>\\n</tr>\\n<tr>\\n<td>Bracket notation with quoted union literal</td>\\n<td><code>$[\',\']</code></td>\\n</tr>\\n<tr>\\n<td>Bracket notation with quoted wildcard literal ?</td>\\n<td><code>$[\'*\']</code></td>\\n</tr>\\n<tr>\\n<td>Bracket notation with quoted wildcard literal on object without key</td>\\n<td><code>$[\'*\']</code></td>\\n</tr>\\n<tr>\\n<td>Bracket notation with spaces</td>\\n<td><code>$[ \'a\' ]</code></td>\\n</tr>\\n<tr>\\n<td>Bracket notation with two literals separated by dot</td>\\n<td><code>$[\'two\'.\'some\']</code></td>\\n</tr>\\n<tr>\\n<td>Bracket notation with two literals separated by dot without quotes</td>\\n<td><code>$[two.some]</code></td>\\n</tr>\\n<tr>\\n<td>Bracket notation without quotes</td>\\n<td><code>$[key]</code></td>\\n</tr>\\n<tr>\\n<td>Current with dot notation</td>\\n<td><code>@.a</code></td>\\n</tr>\\n<tr>\\n<td>Dot bracket notation</td>\\n<td><code>$.[\'key\']</code></td>\\n</tr>\\n<tr>\\n<td>Dot bracket notation with double quotes</td>\\n<td><code>$.[\\"key\\"]</code></td>\\n</tr>\\n<tr>\\n<td>Dot bracket notation without quotes</td>\\n<td><code>$.[key]</code></td>\\n</tr>\\n<tr>\\n<td>Dot notation after recursive descent with extra dot ?</td>\\n<td><code>$...key</code></td>\\n</tr>\\n<tr>\\n<td>Dot notation after union with keys</td>\\n<td><code>$[\'one\',\'three\'].key</code></td>\\n</tr>\\n<tr>\\n<td>Dot notation with dash</td>\\n<td><code>$.key-dash</code></td>\\n</tr>\\n<tr>\\n<td>Dot notation with double quotes</td>\\n<td><code>$.\\"key\\"</code></td>\\n</tr>\\n<tr>\\n<td>Dot notation with double quotes after recursive descent ?</td>\\n<td><code>$..\\"key\\"</code></td>\\n</tr>\\n<tr>\\n<td>Dot notation with empty path</td>\\n<td><code>$.</code></td>\\n</tr>\\n<tr>\\n<td>Dot notation with key named length on array</td>\\n<td><code>$.length</code></td>\\n</tr>\\n<tr>\\n<td>Dot notation with key root literal</td>\\n<td><code>$.$</code></td>\\n</tr>\\n<tr>\\n<td>Dot notation with non ASCII key</td>\\n<td><code>$.??</code></td>\\n</tr>\\n<tr>\\n<td>Dot notation with number</td>\\n<td><code>$.2</code></td>\\n</tr>\\n<tr>\\n<td>Dot notation with number -1</td>\\n<td><code>$.-1</code></td>\\n</tr>\\n<tr>\\n<td>Dot notation with single quotes</td>\\n<td><code>$.\'key\'</code></td>\\n</tr>\\n<tr>\\n<td>Dot notation with single quotes after recursive descent ?</td>\\n<td><code>$..\'key\'</code></td>\\n</tr>\\n<tr>\\n<td>Dot notation with single quotes and dot</td>\\n<td><code>$.\'some.key\'</code></td>\\n</tr>\\n<tr>\\n<td>Dot notation with space padded key</td>\\n<td><code>$. a</code></td>\\n</tr>\\n<tr>\\n<td>Dot notation with wildcard after recursive descent on scalar ?</td>\\n<td><code>$..*</code></td>\\n</tr>\\n<tr>\\n<td>Dot notation without dot</td>\\n<td><code>$a</code></td>\\n</tr>\\n<tr>\\n<td>Dot notation without root</td>\\n<td><code>.key</code></td>\\n</tr>\\n<tr>\\n<td>Dot notation without root and dot</td>\\n<td><code>key</code></td>\\n</tr>\\n<tr>\\n<td>Empty</td>\\n<td><code>n/a</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression on object</td>\\n<td><code>$[?(@.key)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression after dot notation with wildcard after recursive descent ?</td>\\n<td><code>$..*[?(@.id&gt;2)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression after recursive descent ?</td>\\n<td><code>$..[?(@.id==2)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with addition</td>\\n<td><code>$[?(@.key+50==100)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with boolean and operator and value false</td>\\n<td><code>$[?(@.key&gt;0 &amp;&amp; false)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with boolean and operator and value true</td>\\n<td><code>$[?(@.key&gt;0 &amp;&amp; true)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with boolean or operator and value false</td>\\n<td><code>$[?(@.key&gt;0 &amp;#124;&amp;#124; false)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with boolean or operator and value true</td>\\n<td><code>$[?(@.key&gt;0 &amp;#124;&amp;#124; true)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with bracket notation with -1</td>\\n<td><code>$[?(@[-1]==2)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with bracket notation with number on object</td>\\n<td><code>$[?(@[1]==\'b\')]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with current object</td>\\n<td><code>$[?(@)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with different ungrouped operators</td>\\n<td><code>$[?(@.a &amp;&amp; @.b &amp;#124;&amp;#124; @.c)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with division</td>\\n<td><code>$[?(@.key/10==5)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with dot notation with dash</td>\\n<td><code>$[?(@.key-dash == \'value\')]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with dot notation with number</td>\\n<td><code>$[?(@.2 == \'second\')]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with dot notation with number on array</td>\\n<td><code>$[?(@.2 == \'third\')]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with empty expression</td>\\n<td><code>$[?()]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with equals</td>\\n<td><code>$[?(@.key==42)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with equals on array of numbers</td>\\n<td><code>$[?(@==42)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with equals on object</td>\\n<td><code>$[?(@.key==42)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with equals array</td>\\n<td><code>$[?(@.d==[\\"v1\\",\\"v2\\"])]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with equals array for array slice with range 1</td>\\n<td><code>$[?(@[0:1]==[1])]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with equals array for dot notation with star</td>\\n<td><code>$[?(@.*==[1,2])]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with equals array or equals true</td>\\n<td><code>$[?(@.d==[\\"v1\\",\\"v2\\"] &amp;#124;&amp;#124; (@.d == true))]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with equals array with single quotes</td>\\n<td><code>$[?(@.d==[\'v1\',\'v2\'])]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with equals boolean expression value</td>\\n<td><code>$[?((@.key&lt;44)==false)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with equals false</td>\\n<td><code>$[?(@.key==false)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with equals null</td>\\n<td><code>$[?(@.key==null)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with equals number for array slice with range 1</td>\\n<td><code>$[?(@[0:1]==1)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with equals number for bracket notation with star</td>\\n<td><code>$[?(@[*]==2)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with equals number for dot notation with star</td>\\n<td><code>$[?(@.*==2)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with equals number with fraction</td>\\n<td><code>$[?(@.key==-0.123e2)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with equals number with leading zeros</td>\\n<td><code>$[?(@.key==010)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with equals object</td>\\n<td><code>$[?(@.d==&lbrace;\\"k\\":\\"v\\"&rbrace;)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with equals string</td>\\n<td><code>$[?(@.key==\\"value\\")]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with equals string with unicode character escape</td>\\n<td><code>$[?(@.key==\\"Mot\\\\u00f6rhead\\")]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with equals true</td>\\n<td><code>$[?(@.key==true)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with equals with path and path</td>\\n<td><code>$[?(@.key1==@.key2)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with equals with root reference</td>\\n<td><code>$.items[?(@.key==$.value)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with greater than</td>\\n<td><code>$[?(@.key&gt;42)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with greater than or equal</td>\\n<td><code>$[?(@.key&gt;=42)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with in array of values</td>\\n<td><code>$[?(@.d in [2, 3])]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with in current object</td>\\n<td><code>$[?(2 in @.d)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with length free function</td>\\n<td><code>$[?(length(@) == 4)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with length function</td>\\n<td><code>$[?(@.length() == 4)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with length property</td>\\n<td><code>$[?(@.length == 4)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with less than</td>\\n<td><code>$[?(@.key&lt;42)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with less than or equal</td>\\n<td><code>$[?(@.key&lt;=42)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with local dot key and null in data</td>\\n<td><code>$[?(@.key=\'value\')]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with multiplication</td>\\n<td><code>$[?(@.key*2==100)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with negation and equals</td>\\n<td><code>$[?(!(@.key==42))]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with negation and equals array or equals true</td>\\n<td><code>$[?(!(@.d==[\\"v1\\",\\"v2\\"]) &amp;#124;&amp;#124; (@.d == true))]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with negation and less than</td>\\n<td><code>$[?(!(@.key&lt;42))]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with negation and without value</td>\\n<td><code>$[?(!@.key)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with non singular existence test</td>\\n<td><code>$[?(@.a.*)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with not equals</td>\\n<td><code>$[?(@.key!=42)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with not equals array or equals true</td>\\n<td><code>$[?((@.d!=[\\"v1\\",\\"v2\\"]) &amp;#124;&amp;#124; (@.d == true))]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with parent axis operator</td>\\n<td><code>$[*].bookmarks[?(@.page == 45)]^^^</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with regular expression</td>\\n<td><code>$[?(@.name=~/hello.*/)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with regular expression from member</td>\\n<td><code>$[?(@.name=~/@.pattern/)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with set wise comparison to scalar</td>\\n<td><code>$[?(@[*]&gt;=4)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with set wise comparison to set</td>\\n<td><code>$.x[?(@[*]&gt;=$.y[*])]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with single equal</td>\\n<td><code>$[?(@.key=42)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with subfilter</td>\\n<td><code>$[?(@.a[?(@.price&gt;10)])]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with subpaths deeply nested</td>\\n<td><code>$[?(@.a.b.c==3)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with subtraction</td>\\n<td><code>$[?(@.key-50==-100)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with triple equal</td>\\n<td><code>$[?(@.key===42)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with value</td>\\n<td><code>$[?(@.key)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with value after recursive descent ?</td>\\n<td><code>$..[?(@.id)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with value false</td>\\n<td><code>$[?(false)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with value from recursive descent</td>\\n<td><code>$[?(@..child)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with value null</td>\\n<td><code>$[?(null)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression with value true</td>\\n<td><code>$[?(true)]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression without parens</td>\\n<td><code>$[?@.key==42]</code></td>\\n</tr>\\n<tr>\\n<td>Filter expression without value</td>\\n<td><code>$[?(@.key)]</code></td>\\n</tr>\\n<tr>\\n<td>Function sum</td>\\n<td><code>$.data.sum()</code></td>\\n</tr>\\n<tr>\\n<td>Parens notation</td>\\n<td><code>$(key,more)</code></td>\\n</tr>\\n<tr>\\n<td>Recursive descent ?</td>\\n<td><code>$..</code></td>\\n</tr>\\n<tr>\\n<td>Recursive descent after dot notation ?</td>\\n<td><code>$.key..</code></td>\\n</tr>\\n<tr>\\n<td>Root on scalar</td>\\n<td><code>$</code></td>\\n</tr>\\n<tr>\\n<td>Root on scalar false</td>\\n<td><code>$</code></td>\\n</tr>\\n<tr>\\n<td>Root on scalar true</td>\\n<td><code>$</code></td>\\n</tr>\\n<tr>\\n<td>Script expression</td>\\n<td><code>$[(@.length-1)]</code></td>\\n</tr>\\n<tr>\\n<td>Union with duplication from array</td>\\n<td><code>$[0,0]</code></td>\\n</tr>\\n<tr>\\n<td>Union with duplication from object</td>\\n<td><code>$[\'a\',\'a\']</code></td>\\n</tr>\\n<tr>\\n<td>Union with filter</td>\\n<td><code>$[?(@.key&lt;3),?(@.key&gt;6)]</code></td>\\n</tr>\\n<tr>\\n<td>Union with keys</td>\\n<td><code>$[\'key\',\'another\']</code></td>\\n</tr>\\n<tr>\\n<td>Union with keys on object without key</td>\\n<td><code>$[\'missing\',\'key\']</code></td>\\n</tr>\\n<tr>\\n<td>Union with keys after array slice</td>\\n<td><code>$[:][\'c\',\'d\']</code></td>\\n</tr>\\n<tr>\\n<td>Union with keys after bracket notation</td>\\n<td><code>$[0][\'c\',\'d\']</code></td>\\n</tr>\\n<tr>\\n<td>Union with keys after dot notation with wildcard</td>\\n<td><code>$.*[\'c\',\'d\']</code></td>\\n</tr>\\n<tr>\\n<td>Union with keys after recursive descent ?</td>\\n<td><code>$..[\'c\',\'d\']</code></td>\\n</tr>\\n<tr>\\n<td>Union with repeated matches after dot notation with wildcard</td>\\n<td><code>$.*[0,:5]</code></td>\\n</tr>\\n<tr>\\n<td>Union with slice and number</td>\\n<td><code>$[1:3,4]</code></td>\\n</tr>\\n<tr>\\n<td>Union with spaces</td>\\n<td><code>$[ 0 , 1 ]</code></td>\\n</tr>\\n<tr>\\n<td>Union with wildcard and number</td>\\n<td><code>$[*,1]</code></td>\\n</tr>\\n</tbody>\\n</table>\\n</details>"},{"id":"sunsetting-shields-custom-logos","metadata":{"permalink":"/blog/sunsetting-shields-custom-logos","editUrl":"https://github.com/badges/shields/tree/master/frontend/blog/2024-07-10-sunsetting-shields-custom-logos.md","source":"@site/blog/2024-07-10-sunsetting-shields-custom-logos.md","title":"Sunsetting Shields custom logos","description":"Following discussions in #9476, we\'ve gone ahead and deleted all custom logos that were maintained on the Shields.io side (bitcoin, dependabot, gitlab, npm, paypal, serverfault, stackexchange, superuser, telegram, travis), and will solely rely on the Simple-Icons project to provide named logos for our badges from now on. If you were using a Shields custom logo, you will have transparently switched over to the corresponding Simple-Icon and do not need to make changes to your badges.","date":"2024-07-10T00:00:00.000Z","tags":[],"readingTime":2.69,"hasTruncateMarker":false,"authors":[{"name":"PyvesB","title":"Shields.io Core Team","url":"https://github.com/PyvesB","image_url":"https://avatars.githubusercontent.com/u/10694593","imageURL":"https://avatars.githubusercontent.com/u/10694593","socials":{},"key":null,"page":null}],"frontMatter":{"slug":"sunsetting-shields-custom-logos","title":"Sunsetting Shields custom logos","authors":{"name":"PyvesB","title":"Shields.io Core Team","url":"https://github.com/PyvesB","image_url":"https://avatars.githubusercontent.com/u/10694593","imageURL":"https://avatars.githubusercontent.com/u/10694593"},"tags":[]},"unlisted":false,"prevItem":{"title":"Our response to RCE Security Advisory","permalink":"/blog/GHSA-rxvx-x284-4445"},"nextItem":{"title":"Simple Icons 13","permalink":"/blog/simple-icons-13"}},"content":"Following discussions in [#9476](https://github.com/badges/shields/issues/9476), we\'ve gone ahead and deleted all custom logos that were maintained on the Shields.io side (bitcoin, dependabot, gitlab, npm, paypal, serverfault, stackexchange, superuser, telegram, travis), and will solely rely on the [Simple-Icons project](https://github.com/simple-icons/simple-icons) to provide named logos for our badges from now on. If you were using a Shields custom logo, you will have transparently switched over to the corresponding Simple-Icon and do not need to make changes to your badges.\\n\\nThe reasons behind this decision include the following:\\n\\n- reducing code complexity and induced overhead by deleting several dozens lines of code.\\n- reducing maintenance load; we received regular pull requests to add logos that do not comply with our guidelines, or various other related questions.\\n- providing a less confusing user experience; all named logos now behave in the same way with regards to `logoColor` and other parameters.\\n- reducing frustration for contributors who prepared logo pull requests only to be told that they hadn\'t read the guidelines or that there was a misalignment on the interpretation of said guidelines.\\n- reinforcing Shields.io\'s mission to provide consistent badges, with all named logos now being monochrome.\\n- improving compliance with third-party brands; Simple-Icons regularly reviews whether their icons respect latest brand guidelines, whereas we do not.\\n- unblocking [#4947](https://github.com/badges/shields/issues/4947).\\n\\nWe do acknowledge the fact that some of you voiced your preference for a given Shields custom logo over its Simple-Icons equivalent in [#7684](https://github.com/badges/shields/issues/7684). If you really want to go back to the Shields custom logo, you can leverage [custom logos](https://shields.io/docs/logos#custom-logos) to do so. Here are the corresponding Base64-encoded logo parameters for all our existing logos:\\n\\n| Name | Logo Preview | `logo` Parameter |\\n| --- | :-- | :-- |\\n| bitcoin | ![bitcoin](https://github.com/badges/shields/assets/10694593/20ea99c4-a557-476c-91a8-3b886ce98e5e) | `data:image/svg+xml;base64,` |\\n| dependabot | ![dependabot](https://github.com/badges/shields/assets/10694593/5fb27ba4-f940-4782-bba0-8c01f98cce0e) | `data:image/svg+xml;base64,` |\\n| gitlab | ![gitlab](https://github.com/badges/shields/assets/10694593/e9c8e584-3860-4fe2-b802-2ed7c87f996f) | `data:image/svg+xml;base64,` |\\n| npm | ![npm](https://github.com/badges/shields/assets/10694593/ba629fa3-a467-4c96-b191-62c339faac66) | `data:image/svg+xml;base64,PHN2ZyB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciIHZpZXdCb3g9IjAgMCA0MCA0MCI+PHBhdGggZD0iTTAgMGg0MHY0MEgwVjB6IiBmaWxsPSIjY2IwMDAwIi8+PHBhdGggZmlsbD0iI2ZmZiIgZD0iTTcgN2gyNnYyNmgtN1YxNGgtNnYxOUg3eiIvPjwvc3ZnPgo=` |\\n| paypal | ![paypal](https://github.com/badges/shields/assets/10694593/f2eacc65-7a19-4816-8897-f7723a97b26f) | `data:image/svg+xml;base64,` |\\n| serverfault | ![serverfault](https://github.com/badges/shields/assets/10694593/d1b7a0e5-2465-4009-ba5f-89f364554a46) | `data:image/svg+xml;base64,` |\\n| stackexchange | ![stackexchange](https://github.com/badges/shields/assets/10694593/409644d3-4679-4f0d-9fb9-538215eec8c7) | `data:image/svg+xml;base64,` |\\n| superuser | ![superuser](https://github.com/badges/shields/assets/10694593/f8d0b5ad-5b67-49f8-8989-59256baad56e) | `data:image/svg+xml;base64,` |\\n| telegram | ![telegram](https://github.com/badges/shields/assets/10694593/c5c5acc3-f434-4a8d-a834-6d94a7ffb45a) | `data:image/svg+xml;base64,` |\\n| travis | ![travis](https://github.com/badges/shields/assets/10694593/67110d9b-b825-4ef7-85ff-1bba963121e1) | `data:image/svg+xml;base64,` |\\n\\nFeel free to reach out to us if you have any questions, and happy badging!"},{"id":"simple-icons-13","metadata":{"permalink":"/blog/simple-icons-13","editUrl":"https://github.com/badges/shields/tree/master/frontend/blog/2024-07-05-simpleicons13.md","source":"@site/blog/2024-07-05-simpleicons13.md","title":"Simple Icons 13","description":"Logos on Shields.io are provided by SimpleIcons. We\'ve recently upgraded to SimpleIcons 13. This release removes 65 icons and renames one. A full list of the changes can be found in the release notes.","date":"2024-07-05T00:00:00.000Z","tags":[],"readingTime":0.35,"hasTruncateMarker":false,"authors":[{"name":"chris48s","title":"Shields.io Core Team","url":"https://github.com/chris48s","image_url":"https://avatars.githubusercontent.com/u/6025893","imageURL":"https://avatars.githubusercontent.com/u/6025893","socials":{},"key":null,"page":null}],"frontMatter":{"slug":"simple-icons-13","title":"Simple Icons 13","authors":{"name":"chris48s","title":"Shields.io Core Team","url":"https://github.com/chris48s","image_url":"https://avatars.githubusercontent.com/u/6025893","imageURL":"https://avatars.githubusercontent.com/u/6025893"},"tags":[]},"unlisted":false,"prevItem":{"title":"Sunsetting Shields custom logos","permalink":"/blog/sunsetting-shields-custom-logos"},"nextItem":{"title":"Simple Icons 12","permalink":"/blog/simple-icons-12"}},"content":"Logos on Shields.io are provided by SimpleIcons. We\'ve recently upgraded to SimpleIcons 13. This release removes 65 icons and renames one. A full list of the changes can be found in the [release notes](https://github.com/simple-icons/simple-icons/releases/tag/13.0.0).\\n\\nPlease remember that we are just consumers of SimpleIcons. Decisions about changes and removals are made by the [SimpleIcons](https://github.com/simple-icons/simple-icons) project."},{"id":"simple-icons-12","metadata":{"permalink":"/blog/simple-icons-12","editUrl":"https://github.com/badges/shields/tree/master/frontend/blog/2024-06-01-simpleicons12.md","source":"@site/blog/2024-06-01-simpleicons12.md","title":"Simple Icons 12","description":"Logos on Shields.io are provided by SimpleIcons. We\'ve recently upgraded to SimpleIcons 12. This release removes the following 10 icons:","date":"2024-06-01T00:00:00.000Z","tags":[],"readingTime":0.47,"hasTruncateMarker":false,"authors":[{"name":"chris48s","title":"Shields.io Core Team","url":"https://github.com/chris48s","image_url":"https://avatars.githubusercontent.com/u/6025893","imageURL":"https://avatars.githubusercontent.com/u/6025893","socials":{},"key":null,"page":null}],"frontMatter":{"slug":"simple-icons-12","title":"Simple Icons 12","authors":{"name":"chris48s","title":"Shields.io Core Team","url":"https://github.com/chris48s","image_url":"https://avatars.githubusercontent.com/u/6025893","imageURL":"https://avatars.githubusercontent.com/u/6025893"},"tags":[]},"unlisted":false,"prevItem":{"title":"Simple Icons 13","permalink":"/blog/simple-icons-13"},"nextItem":{"title":"Simple Icons 11","permalink":"/blog/simple-icons-11"}},"content":"Logos on Shields.io are provided by SimpleIcons. We\'ve recently upgraded to SimpleIcons 12. This release removes the following 10 icons:\\n\\n- FITE\\n- Flattr\\n- Google Bard\\n- Integromat\\n- Niantic\\n- Nintendo Network\\n- Rome\\n- Shotcut\\n- Skynet\\n- Twitter\\n\\nAnd renames the following 3:\\n\\n- Airbrake.io to Airbrake\\n- Amazon AWS to Amazon Web Services\\n- RStudio to RStudio IDE\\n\\nMore details can be found in the [release notes](https://github.com/simple-icons/simple-icons/releases/tag/12.0.0).\\n\\nPlease remember that we are just consumers of SimpleIcons. Decisions about changes and removals are made by the [SimpleIcons](https://github.com/simple-icons/simple-icons) project."},{"id":"simple-icons-11","metadata":{"permalink":"/blog/simple-icons-11","editUrl":"https://github.com/badges/shields/tree/master/frontend/blog/2024-01-13-simpleicons11.md","source":"@site/blog/2024-01-13-simpleicons11.md","title":"Simple Icons 11","description":"Logos on Shields.io are provided by SimpleIcons. We\'ve recently upgraded to SimpleIcons 11. This release removes the following 4 icons:","date":"2024-01-13T00:00:00.000Z","tags":[],"readingTime":0.34,"hasTruncateMarker":false,"authors":[{"name":"chris48s","title":"Shields.io Core Team","url":"https://github.com/chris48s","image_url":"https://avatars.githubusercontent.com/u/6025893","imageURL":"https://avatars.githubusercontent.com/u/6025893","socials":{},"key":null,"page":null}],"frontMatter":{"slug":"simple-icons-11","title":"Simple Icons 11","authors":{"name":"chris48s","title":"Shields.io Core Team","url":"https://github.com/chris48s","image_url":"https://avatars.githubusercontent.com/u/6025893","imageURL":"https://avatars.githubusercontent.com/u/6025893"},"tags":[]},"unlisted":false,"prevItem":{"title":"Simple Icons 12","permalink":"/blog/simple-icons-12"},"nextItem":{"title":"Simple Icons 10","permalink":"/blog/simple-icons-10"}},"content":"Logos on Shields.io are provided by SimpleIcons. We\'ve recently upgraded to SimpleIcons 11. This release removes the following 4 icons:\\n\\n- Babylon.js\\n- Hulu\\n- Pepsi\\n- Uno\\n\\nMore details can be found in the [release notes](https://github.com/simple-icons/simple-icons/releases/tag/11.0.0).\\n\\nPlease remember that we are just consumers of SimpleIcons. Decisions about changes and removals are made by the [SimpleIcons](https://github.com/simple-icons/simple-icons) project."},{"id":"simple-icons-10","metadata":{"permalink":"/blog/simple-icons-10","editUrl":"https://github.com/badges/shields/tree/master/frontend/blog/2023-11-29-simpleicons10.md","source":"@site/blog/2023-11-29-simpleicons10.md","title":"Simple Icons 10","description":"Logos on Shields.io are provided by SimpleIcons. We\'ve recently upgraded to SimpleIcons 10. This release removes 45 icons. A full list of the removals can be found in the release notes.","date":"2023-11-29T00:00:00.000Z","tags":[],"readingTime":0.33,"hasTruncateMarker":false,"authors":[{"name":"chris48s","title":"Shields.io Core Team","url":"https://github.com/chris48s","image_url":"https://avatars.githubusercontent.com/u/6025893","imageURL":"https://avatars.githubusercontent.com/u/6025893","socials":{},"key":null,"page":null}],"frontMatter":{"slug":"simple-icons-10","title":"Simple Icons 10","authors":{"name":"chris48s","title":"Shields.io Core Team","url":"https://github.com/chris48s","image_url":"https://avatars.githubusercontent.com/u/6025893","imageURL":"https://avatars.githubusercontent.com/u/6025893"},"tags":[]},"unlisted":false,"prevItem":{"title":"Simple Icons 11","permalink":"/blog/simple-icons-11"},"nextItem":{"title":"Applying filters to GitHub Tag and Release badges","permalink":"/blog/tag-filter"}},"content":"Logos on Shields.io are provided by SimpleIcons. We\'ve recently upgraded to SimpleIcons 10. This release removes 45 icons. A full list of the removals can be found in the [release notes](https://github.com/simple-icons/simple-icons/releases/tag/10.0.0).\\n\\nPlease remember that we are just consumers of SimpleIcons. Decisions about changes and removals are made by the [SimpleIcons](https://github.com/simple-icons/simple-icons) project."},{"id":"tag-filter","metadata":{"permalink":"/blog/tag-filter","editUrl":"https://github.com/badges/shields/tree/master/frontend/blog/2023-07-29-tag-filter.md","source":"@site/blog/2023-07-29-tag-filter.md","title":"Applying filters to GitHub Tag and Release badges","description":"We recently shipped a feature which allows you to pass an arbitrary filter to the GitHub tag and release badges. The filter param can be used to apply a filter to the project\'s tag or release names before selecting the latest from the list. Two constructs are available: * is a wildcard matching zero or more characters, and if the pattern starts with a !, the whole pattern is negated.","date":"2023-07-29T00:00:00.000Z","tags":[],"readingTime":1.06,"hasTruncateMarker":false,"authors":[{"name":"chris48s","title":"Shields.io Core Team","url":"https://github.com/chris48s","image_url":"https://avatars.githubusercontent.com/u/6025893","imageURL":"https://avatars.githubusercontent.com/u/6025893","socials":{},"key":null,"page":null}],"frontMatter":{"slug":"tag-filter","title":"Applying filters to GitHub Tag and Release badges","authors":{"name":"chris48s","title":"Shields.io Core Team","url":"https://github.com/chris48s","image_url":"https://avatars.githubusercontent.com/u/6025893","imageURL":"https://avatars.githubusercontent.com/u/6025893"},"tags":[]},"unlisted":false,"prevItem":{"title":"Simple Icons 10","permalink":"/blog/simple-icons-10"},"nextItem":{"title":"We launched a new frontend","permalink":"/blog/new-frontend"}},"content":"We recently shipped a feature which allows you to pass an arbitrary filter to the GitHub tag and release badges. The `filter` param can be used to apply a filter to the project\'s tag or release names before selecting the latest from the list. Two constructs are available: `*` is a wildcard matching zero or more characters, and if the pattern starts with a `!`, the whole pattern is negated.\\n\\nTo give an example of how this might be useful, we create two types of tags on our GitHub repo: https://github.com/badges/shields/tags There are tags in the format `major.minor.patch` which correspond to our [NPM package releases](https://www.npmjs.com/package/badge-maker?activeTab=versions) and tags in the format `server-YYYY-MM-DD` that correspond to our [docker snapshot releases](https://registry.hub.docker.com/r/shieldsio/shields/tags?page=1&ordering=last_updated).\\n\\nIn our case, this would allow us to make a badge that applies the filter `!server-*` to filter out the snapshot tags and just select the latest package tag.\\n\\n- ![tag badge without filter](https://img.shields.io/github/v/tag/badges/shields) - https://img.shields.io/github/v/tag/badges/shields\\n- ![tag badge with filter](https://img.shields.io/github/v/tag/badges/shields?filter=%21server-%2A) - https://img.shields.io/github/v/tag/badges/shields?filter=%21server-%2A"},{"id":"new-frontend","metadata":{"permalink":"/blog/new-frontend","editUrl":"https://github.com/badges/shields/tree/master/frontend/blog/2023-07-03-new-frontend.md","source":"@site/blog/2023-07-03-new-frontend.md","title":"We launched a new frontend","description":"Alongside the general visual refresh and improvements to look and feel, our new frontend has allowed us to address a number of long-standing feature requests and enhancements:","date":"2023-07-03T00:00:00.000Z","tags":[],"readingTime":0.9,"hasTruncateMarker":false,"authors":[{"name":"chris48s","title":"Shields.io Core Team","url":"https://github.com/chris48s","image_url":"https://avatars.githubusercontent.com/u/6025893","imageURL":"https://avatars.githubusercontent.com/u/6025893","socials":{},"key":null,"page":null}],"frontMatter":{"slug":"new-frontend","title":"We launched a new frontend","authors":{"name":"chris48s","title":"Shields.io Core Team","url":"https://github.com/chris48s","image_url":"https://avatars.githubusercontent.com/u/6025893","imageURL":"https://avatars.githubusercontent.com/u/6025893"},"tags":[]},"unlisted":false,"prevItem":{"title":"Applying filters to GitHub Tag and Release badges","permalink":"/blog/tag-filter"}},"content":"Alongside the general visual refresh and improvements to look and feel, our new frontend has allowed us to address a number of long-standing feature requests and enhancements:\\n\\n- Clearer and more discoverable documentation for our [static](https://shields.io/badges/static-badge), dynamic [json](https://shields.io/badges/dynamic-json-badge)/[xml](https://shields.io/badges/dynamic-xml-badge)/[yaml](https://shields.io/badges/dynamic-yaml-badge) and [endpoint](https://shields.io/badges/endpoint-badge) badges\\n- Improved badge builder interface, with all optional query parameters included in the builder for each badge\\n- Each badge now has its own documentation page, which we can link to. e.g: [https://shields.io/badges/discord](https://shields.io/badges/discord)\\n- Light/dark mode themes\\n- Improved search\\n- Documentation for individual path and query parameters\\n\\nThe new site also comes with big maintenance benefits for the core team. We rely heavily on [docusaurus](https://docusaurus.io/), [docusaurus-openapi](https://github.com/cloud-annotations/docusaurus-openapi), and [docusaurus-search-local](https://github.com/easyops-cn/docusaurus-search-local). This moves us to a mostly declarative setup, massively reducing the amount of custom frontend code we maintain ourselves."}]}}')}}]);